        "path": "Witcher3Trainer/MemoryManager.cs",
        "content": "using System;\r\nusing System.Diagnostics;\r\nusing System.Runtime.InteropServices;\r\n\r\nnamespace Witcher3Trainer\r\n{\r\n    /// <summary>\r\n    /// Provides low-level memory operations for the Witcher 3 process.\r\n    /// Handles reading and writing to the game's memory addresses.\r\n    /// </summary>\r\n    public static class MemoryManager\r\n    {\r\n        // Windows API imports for process memory access\r\n        [DllImport(\"kernel32.dll\")]\r\n        private static extern IntPtr OpenProcess(uint dwDesiredAccess, bool bInheritHandle, int dwProcessId);\r\n\r\n        [DllImport(\"kernel32.dll\")]\r\n        private static extern bool ReadProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesRead);\r\n\r\n        [DllImport(\"kernel32.dll\")]\r\n        private static extern bool WriteProcessMemory(IntPtr hProcess, IntPtr lpBaseAddress, byte[] lpBuffer, int dwSize, out int lpNumberOfBytesWritten);\r\n\r\n        [DllImport(\"kernel32.dll\")]\r\n        private static extern bool CloseHandle(IntPtr hObject);\r\n\r\n        private const uint PROCESS_VM_READ = 0x0010;\r\n        private const uint PROCESS_VM_WRITE = 0x0020;\r\n        private const uint PROCESS_VM_OPERATION = 0x0008;\r\n\r\n        private static IntPtr _processHandle;\r\n        private static int _processId;\r\n\r\n        /// <summary>\r\n        /// Attempts to attach to the Witcher 3 game process.\r\n        /// </summary>\r\n        /// <returns>True if successfully attached, false otherwise.</returns>\r\n        public static bool AttachToGame()\r\n        {\r\n            Process[] processes = Process.GetProcessesByName(\"witcher3\");\r\n            if (processes.Length == 0)\r\n            {\r\n                Console.WriteLine(\"[ERROR] Witcher 3 process not found. Make sure the game is running.\");\r\n                return false;\r\n            }\r\n\r\n            _processId = processes[0].Id;\r\n            _processHandle = OpenProcess(PROCESS_VM_READ | PROCESS_VM_WRITE | PROCESS_VM_OPERATION, false, _processId);\r\n\r\n            if (_processHandle == IntPtr.Zero)\r\n            {\r\n                Console.WriteLine(\"[ERROR] Failed to open process handle. Try running as administrator.\");\r\n                return false;\r\n            }\r\n\r\n            Console.WriteLine($\"[INFO] Attached to Witcher 3 process (PID: {_processId}).\");\r\n            return true;\r\n        }\r\n\r\n        /// <summary>\r\n        /// Reads a 4-byte integer from the specified memory address.\r\n        /// </summary>\r\n        /// <param name=\"address\">Memory address to read from.</param>\r\n        /// <returns>The integer value read, or 0 on failure.</returns>\r\n        public static int ReadInt(IntPtr address)\r\n        {\r\n            byte[] buffer = new byte[4];\r\n            if (ReadProcessMemory(_processHandle, address, buffer, 4, out int bytesRead) && bytesRead == 4)\r\n            {\r\n                return BitConverter.ToInt32(buffer, 0);\r\n            }\r\n            return 0;\r\n        }\r\n\r\n        /// <summary>\r\n        /// Writes a 4-byte integer to the specified memory address.\r\n        /// </summary>\r\n        /// <param name=\"address\">Memory address to write to.</param>\r\n        /// <param name=\"value\">The integer value to write.</param>\r\n        /// <returns>True if the write succeeded.</returns>\r\n        public static bool WriteInt(IntPtr address, int value)\r\n        {\r\n            byte[] buffer = BitConverter.GetBytes(value);\r\n            return WriteProcessMemory(_processHandle, address, buffer, 4, out int bytesWritten) && bytesWritten == 4;\r\n        }\r\n\r\n        /// <summary>\r\n        /// Reads a 4-byte float from the specified memory address.\r\n        /// </summary>\r\n        /// <param name=\"address\">Memory address to read from.</param>\r\n        /// <returns>The float value read, or 0.0f on failure.</returns>\r\n        public static float ReadFloat(IntPtr address)\r\n        {\r\n            byte[] buffer = new byte[4];\r\n            if (ReadProcessMemory(_processHandle, address, buffer, 4, out int bytesRead) && bytesRead == 4)\r\n            {\r\n                return BitConverter.ToSingle(buffer, 0);\r\n            }\r\n            return 0.0f;\r\n        }\r\n\r\n        /// <summary>\r\n        /// Writes a 4-byte float to the specified memory address.\r\n        /// </summary>\r\n        /// <param name=\"address\">Memory address to write to.</param>\r\n        /// <param name=\"value\">The float value to write.</param>\r\n        /// <returns>True if the write succeeded.</returns>\r\n        public static bool WriteFloat(IntPtr address, float value)\r\n        {\r\n            byte[] buffer = BitConverter.GetBytes(value);\r\n            return WriteProcessMemory(_processHandle, address, buffer, 4, out int bytesWritten) && bytesWritten == 4;\r\n        }\r\n\r\n        /// <summary>\r\n        /// Releases the handle to the game process.\r\n        /// </summary>\r\n        public static void Detach()\r\n        {\r\n            if (_processHandle != IntPtr.Zero)\r\n            {\r\n                CloseHandle(_processHandle);\r\n                _processHandle = IntPtr.Zero;\r\n                Console.WriteLine(\"[INFO] Detached from Witcher 3 process.\");\r\n            }\r\n        }\r\n    }\r\n}\r\n"
    },
