        "path": "Witcher3Trainer/Program.cs",
        "content": "using System;\r\n\r\nnamespace Witcher3Trainer\r\n{\r\n    /// <summary>\r\n    /// Main entry point for the Witcher 3 Wild Hunt Trainer.\r\n    /// Provides a console-based interface for activating cheats.\r\n    /// </summary>\r\n    class Program\r\n    {\r\n        static void Main(string[] args)\r\n        {\r\n            Console.WriteLine(\"========================================\");\r\n            Console.WriteLine(\"  The Witcher 3: Wild Hunt Trainer v1.0\");\r\n            Console.WriteLine(\"========================================\");\r\n            Console.WriteLine();\r\n\r\n            if (!MemoryManager.AttachToGame())\r\n            {\r\n                Console.WriteLine(\"Press any key to exit...\");\r\n                Console.ReadKey();\r\n                return;\r\n            }\r\n\r\n            bool running = true;\r\n            while (running)\r\n            {\r\n                Console.WriteLine();\r\n                Console.WriteLine(\"Available commands:\");\r\n                Console.WriteLine(\"  1 - Infinite Health\");\r\n                Console.WriteLine(\"  2 - Infinite Stamina\");\r\n                Console.WriteLine(\"  3 - Reset Toxicity\");\r\n                Console.WriteLine(\"  4 - Add 1000 Gold\");\r\n                Console.WriteLine(\"  5 - Add 5000 XP\");\r\n                Console.WriteLine(\"  6 - Set Level to 50\");\r\n                Console.WriteLine(\"  7 - Exit\");\r\n                Console.Write(\"Enter choice: \");\r\n\r\n                string input = Console.ReadLine();\r\n                Console.WriteLine();\r\n\r\n                switch (input)\r\n                {\r\n                    case \"1\":\r\n                        if (TrainerFeatures.SetInfiniteHealth())\r\n                            Console.WriteLine(\"[SUCCESS] Health set to maximum.\");\r\n                        else\r\n                            Console.WriteLine(\"[FAIL] Could not set health.\");\r\n                        break;\r\n                    case \"2\":\r\n                        if (TrainerFeatures.SetInfiniteStamina())\r\n                            Console.WriteLine(\"[SUCCESS] Stamina set to maximum.\");\r\n                        else\r\n                            Console.WriteLine(\"[FAIL] Could not set stamina.\");\r\n                        break;\r\n                    case \"3\":\r\n                        if (TrainerFeatures.ResetToxicity())\r\n
